import itertools
import numpy as np

def calculate_probability(coins):
    return np.prod(coins)

def greedy_selection(coins, n):
    sorted_coins = sorted(coins, reverse=True)
    return sorted_coins[:n]

def brute_force_selection(coins, n):
    best_set = []
    best_prob = 0
    for combination in itertools.combinations(coins, n):
        prob = calculate_probability(combination)
        if prob > best_prob:
            best_prob = prob
            best_set = combination
    return best_set

def dynamic_programming_selection(coins, n):
    dp = [[0] * (n + 1) for _ in range(len(coins) + 1)]
    for i in range(1, len(coins) + 1):
        for j in range(1, n + 1):
            dp[i][j] = dp[i - 1][j]
            if j > 0:
                dp[i][j] = max(dp[i][j], dp[i - 1][j - 1] + coins[i - 1])
    selected_coins = []
    j = n
    for i in range(len(coins), 0, -1):
        if dp[i][j] != dp[i - 1][j]:
            selected_coins.append(coins[i - 1])
            j -= 1
    return selected_coins

def main():
    coins = [0.1, 0.5, 0.7, 0.9, 0.3, 0.6, 0.8, 0.4]
    n = 4

    greedy_set = greedy_selection(coins, n)
    brute_force_set = brute_force_selection(coins, n)
    dp_set = dynamic_programming_selection(coins, n)

    print("Greedy Selection:", greedy_set)
    print("Brute Force Selection:", brute_force_set)
    print("Dynamic Programming Selection:", dp_set)

