import itertools
import numpy as np

def biased_coin_tosses(coins, n):
    heads_count = 0
    for coin in coins:
        if np.random.rand() < coin:
            heads_count += 1
    return heads_count

def method_random_selection(coins, n, trials=10000):
    successful_trials = 0
    for _ in range(trials):
        selected_coins = np.random.choice(coins, n, replace=False)
        if biased_coin_tosses(selected_coins, n) == n:
            successful_trials += 1
    return successful_trials / trials

def method_combinatorial_selection(coins, n, trials=10000):
    successful_trials = 0
    for selected_coins in itertools.combinations(coins, n):
        if biased_coin_tosses(selected_coins, n) == n:
            successful_trials += 1
    return successful_trials / trials

def method_greedy_selection(coins, n, trials=10000):
    successful_trials = 0
    sorted_coins = sorted(coins, reverse=True)
    selected_coins = sorted_coins[:n]
    for _ in range(trials):
        if biased_coin_tosses(selected_coins, n) == n:
            successful_trials += 1
    return successful_trials / trials

# Example usage
